import { forwardRef, type HTMLAttributes, type ReactNode } from 'react';
import { cls, useNamespace } from '../../utils';

export type StepStatus = 'wait' | 'process' | 'finish' | 'error' | 'success';

export interface StepProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
  /** Step title. */
  title?: ReactNode;
  /** Step description shown below the title. */
  description?: ReactNode;
  /** Custom icon rendered inside the step marker (overrides the number/check). */
  icon?: ReactNode;
  /** Explicit status, overriding the value derived from `active`. */
  status?: StepStatus;
  children?: ReactNode;
}

function CheckIcon() {
  return (
    <svg viewBox="0 0 1024 1024" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
      <path
        fill="currentColor"
        d="M406.656 706.944 195.84 496.256a32 32 0 1 0-45.248 45.248l256 256 512-512a32 32 0 0 0-45.248-45.248L406.592 706.944z"
      />
    </svg>
  );
}

function CloseIcon() {
  return (
    <svg viewBox="0 0 1024 1024" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
      <path
        fill="currentColor"
        d="M764.288 214.592 512 466.88 259.712 214.592a31.936 31.936 0 0 0-45.12 45.12L466.752 512 214.528 764.224a31.936 31.936 0 1 0 45.12 45.184L512 557.184l252.288 252.288a31.936 31.936 0 0 0 45.12-45.12L557.12 512.064l252.288-252.352a31.936 31.936 0 1 0-45.12-45.184z"
      />
    </svg>
  );
}

/**
 * Internal props injected by `Steps` when it clones each child. Consumers only
 * supply `StepProps`; the layout-derived values below are computed by the parent.
 */
export interface StepInternalProps {
  /** Zero-based index of this step within `Steps`. */
  stepIndex?: number;
  /** Resolved status, after merging `active` position with any explicit `status`. */
  resolvedStatus?: StepStatus;
  /** Whether this step is the active (current) one. */
  isCurrent?: boolean;
  /** Whether a connector line should be rendered after this step. */
  hasLine?: boolean;
  /** Whether the connector line should be drawn as filled (finished). */
  lineFilled?: boolean;
  /** Layout direction inherited from `Steps`. */
  direction?: 'horizontal' | 'vertical';
  /** Center icon/title under each other (horizontal only). */
  alignCenter?: boolean;
  /** Simplified rendering without descriptions/connectors. */
  simple?: boolean;
  /** Flex basis applied to the step, from `Steps`' `space`. */
  spaceStyle?: string | number;
}

export const Step = forwardRef<HTMLDivElement, StepProps & StepInternalProps>(function Step(
  props,
  ref,
) {
  const {
    title,
    description,
    icon,
    // `status` is consumed by Steps to compute `resolvedStatus`; ignore it here.
    status: _status,
    stepIndex = 0,
    resolvedStatus = 'wait',
    isCurrent = false,
    hasLine = false,
    lineFilled = false,
    direction = 'horizontal',
    alignCenter = false,
    simple = false,
    spaceStyle,
    className,
    style,
    children,
    ...rest
  } = props;
  void _status;

  const ns = useNamespace('step');

  const classes = cls(
    ns.b(),
    ns.m(direction),
    ns.is(resolvedStatus),
    ns.is('center', alignCenter && direction === 'horizontal' && !simple),
    ns.is('simple', simple),
    ns.is('flex', spaceStyle !== undefined),
    className,
  );

  const mergedStyle =
    spaceStyle === undefined
      ? style
      : {
          flexBasis: typeof spaceStyle === 'number' ? `${spaceStyle}px` : spaceStyle,
          ...style,
        };

  let marker: ReactNode;
  if (icon) {
    marker = icon;
  } else if (resolvedStatus === 'finish' || resolvedStatus === 'success') {
    marker = <CheckIcon />;
  } else if (resolvedStatus === 'error') {
    marker = <CloseIcon />;
  } else {
    marker = stepIndex + 1;
  }

  return (
    <div
      ref={ref}
      className={classes}
      style={mergedStyle}
      role="listitem"
      aria-current={isCurrent ? 'step' : undefined}
      {...rest}
    >
      <div className={ns.e('head')}>
        <div className={ns.e('icon')} aria-hidden={icon ? undefined : true}>
          {marker}
        </div>
        {hasLine && !simple && (
          <div className={cls(ns.e('line'), ns.is('filled', lineFilled))} aria-hidden="true">
            <span className={ns.e('line-inner')} />
          </div>
        )}
      </div>
      <div className={ns.e('main')}>
        {title !== undefined && <div className={ns.e('title')}>{title}</div>}
        {!simple && description !== undefined && (
          <div className={ns.e('description')}>{description}</div>
        )}
        {children}
      </div>
    </div>
  );
});

import {
  Children,
  cloneElement,
  forwardRef,
  type HTMLAttributes,
  isValidElement,
  type ReactElement,
  type ReactNode,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { Step, type StepInternalProps, type StepProps, type StepStatus } from './Step';

export type StepsDirection = 'horizontal' | 'vertical';

export interface StepsProps extends HTMLAttributes<HTMLDivElement> {
  /** Index of the current (active) step. */
  active?: number;
  /** Layout direction. */
  direction?: StepsDirection;
  /** Center the icon and title under each other (horizontal only). */
  alignCenter?: boolean;
  /** Render a compact, simplified step bar. */
  simple?: boolean;
  /** Fixed spacing between steps (px number or any CSS length). */
  space?: number | string;
  /** Status applied to steps before the active one. */
  finishStatus?: StepStatus;
  /** Status applied to the active step. */
  processStatus?: StepStatus;
  /** `Step` elements. */
  children?: ReactNode;
}

function isStep(child: ReactNode): child is ReactElement<StepProps> {
  return isValidElement(child) && child.type === Step;
}

export const Steps = forwardRef<HTMLDivElement, StepsProps>(function Steps(props, ref) {
  const {
    active = 0,
    direction = 'horizontal',
    alignCenter = false,
    simple = false,
    space,
    finishStatus = 'finish',
    processStatus = 'process',
    className,
    children,
    ...rest
  } = props;

  const ns = useNamespace('steps');

  const steps = Children.toArray(children).filter(isStep);
  const total = steps.length;

  const classes = cls(
    ns.b(),
    ns.m(simple ? 'simple' : direction),
    ns.is('center', alignCenter && direction === 'horizontal' && !simple),
    className,
  );

  return (
    <div ref={ref} className={classes} role="list" {...rest}>
      {steps.map((step, index) => {
        // Position-derived status, which the step's own `status` may override.
        const positional: StepStatus =
          index < active ? finishStatus : index === active ? processStatus : 'wait';
        const resolvedStatus = step.props.status ?? positional;
        const isCurrent = index === active;
        const isLast = index === total - 1;
        // The connector after a step is filled once the next step has begun, i.e.
        // when the current step is finished/processed (its index is below active).
        const lineFilled = index < active;

        const internal: StepInternalProps = {
          stepIndex: index,
          resolvedStatus,
          isCurrent,
          hasLine: !isLast,
          lineFilled,
          direction,
          alignCenter,
          simple,
          spaceStyle: space,
        };

        return cloneElement(step, { key: step.key ?? index, ...internal });
      })}
    </div>
  );
});

.ec-steps {
  --ec-steps-icon-size: 28px;
  --ec-steps-wait-color: var(--ec-text-color-placeholder);
  --ec-steps-wait-border-color: var(--ec-border-color);
  --ec-steps-process-color: var(--ec-color-primary);
  --ec-steps-finish-color: var(--ec-color-primary);
  --ec-steps-error-color: var(--ec-color-danger);
  --ec-steps-success-color: var(--ec-color-success);
  --ec-steps-title-color: var(--ec-text-color-primary);
  --ec-steps-description-color: var(--ec-text-color-secondary);
  --ec-steps-line-color: var(--ec-border-color-light);

  display: flex;
  box-sizing: border-box;
  font-family: var(--ec-font-family);
  font-size: var(--ec-font-size-base);
  color: var(--ec-text-color-primary);
}

.ec-steps *,
.ec-steps *::before,
.ec-steps *::after {
  box-sizing: border-box;
}

.ec-steps--horizontal {
  flex-direction: row;
}

.ec-steps--vertical {
  flex-direction: column;
}

.ec-steps--simple {
  flex-direction: row;
  align-items: center;
  padding: 13px 8%;
  border-radius: var(--ec-border-radius-base);
  background-color: var(--ec-fill-color-light);
}

/* ---- Individual step ---- */
.ec-step {
  position: relative;
  display: flex;
  flex: 1;
  box-sizing: border-box;
}

.ec-step.is-flex {
  flex: 0 0 auto;
}

.ec-step--horizontal {
  flex-direction: row;
  align-items: flex-start;
}

.ec-step--horizontal:last-of-type {
  flex: 0 0 auto;
}

.ec-step--vertical {
  flex-direction: row;
  align-items: stretch;
  padding-bottom: 0;
}

/* ---- Head: icon + connector ---- */
.ec-step__head {
  position: relative;
  display: flex;
  align-items: center;
  flex-shrink: 0;
}

.ec-step--vertical .ec-step__head {
  flex-direction: column;
  margin-right: 16px;
}

.ec-step__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  width: var(--ec-steps-icon-size);
  height: var(--ec-steps-icon-size);
  flex-shrink: 0;
  font-size: var(--ec-font-size-base);
  font-weight: var(--ec-font-weight-primary);
  line-height: 1;
  color: var(--ec-steps-wait-color);
  background-color: var(--ec-fill-color-blank);
  border: 2px solid var(--ec-steps-wait-border-color);
  border-radius: 50%;
  transition: var(--ec-transition-all);
}

.ec-step__icon svg {
  width: 1em;
  height: 1em;
}

/* ---- Connector line ---- */
.ec-step__line {
  position: relative;
  flex: 1;
  background-color: var(--ec-steps-line-color);
}

.ec-step--horizontal .ec-step__line {
  height: 2px;
  margin: 0 8px;
  min-width: 12px;
}

.ec-step--vertical .ec-step__line {
  width: 2px;
  margin: 8px 0;
  min-height: 12px;
}

.ec-step__line-inner {
  display: block;
  position: absolute;
  inset: 0;
  width: 0;
  height: 100%;
  background-color: var(--ec-steps-finish-color);
  transition: var(--ec-transition-all);
}

.ec-step--vertical .ec-step__line-inner {
  width: 100%;
  height: 0;
}

.ec-step__line.is-filled .ec-step__line-inner {
  width: 100%;
  height: 100%;
}

/* ---- Main: title + description ---- */
.ec-step__main {
  display: flex;
  flex-direction: column;
  padding-left: 10px;
  flex: 1;
}

.ec-step--vertical .ec-step__main {
  padding-left: 0;
  padding-bottom: 12px;
}

.ec-step__title {
  font-size: var(--ec-font-size-medium);
  font-weight: var(--ec-font-weight-primary);
  line-height: var(--ec-steps-icon-size);
  color: var(--ec-steps-title-color);
}

.ec-step__description {
  margin-top: 2px;
  font-size: var(--ec-font-size-small);
  line-height: 1.4;
  color: var(--ec-steps-description-color);
}

/* ---- Center alignment (horizontal) ---- */
.ec-step.is-center {
  flex-direction: column;
  align-items: center;
  text-align: center;
}

.ec-step.is-center .ec-step__head {
  width: 100%;
  flex-direction: row;
  justify-content: center;
}

.ec-step.is-center .ec-step__line {
  position: absolute;
  top: calc(var(--ec-steps-icon-size) / 2 - 1px);
  left: calc(50% + var(--ec-steps-icon-size) / 2 + 8px);
  right: calc(-50% + var(--ec-steps-icon-size) / 2 + 8px);
  flex: none;
  margin: 0;
}

.ec-step.is-center .ec-step__main {
  align-items: center;
  padding-left: 0;
  margin-top: 8px;
}

/* ---- Status colours ---- */
.ec-step.is-process .ec-step__icon {
  color: var(--ec-color-primary-contrast);
  background-color: var(--ec-steps-process-color);
  border-color: var(--ec-steps-process-color);
}

.ec-step.is-process .ec-step__title {
  color: var(--ec-steps-process-color);
  font-weight: var(--ec-font-weight-primary);
}

.ec-step.is-finish .ec-step__icon,
.ec-step.is-success .ec-step__icon {
  color: var(--ec-steps-finish-color);
  background-color: var(--ec-fill-color-blank);
  border-color: var(--ec-steps-finish-color);
}

.ec-step.is-success .ec-step__icon {
  color: var(--ec-steps-success-color);
  border-color: var(--ec-steps-success-color);
}

.ec-step.is-finish .ec-step__title,
.ec-step.is-success .ec-step__title {
  color: var(--ec-steps-title-color);
}

.ec-step.is-error .ec-step__icon {
  color: var(--ec-color-danger-contrast);
  background-color: var(--ec-steps-error-color);
  border-color: var(--ec-steps-error-color);
}

.ec-step.is-error .ec-step__title {
  color: var(--ec-steps-error-color);
}

.ec-step.is-wait .ec-step__icon {
  color: var(--ec-steps-wait-color);
  border-color: var(--ec-steps-wait-border-color);
}

.ec-step.is-wait .ec-step__title {
  color: var(--ec-text-color-secondary);
}

/* ---- Simple variant ---- */
.ec-step.is-simple {
  flex-direction: row;
  align-items: center;
}

.ec-step.is-simple .ec-step__head {
  margin-right: 8px;
}

.ec-step.is-simple .ec-step__icon {
  width: 16px;
  height: 16px;
  font-size: var(--ec-font-size-extra-small);
  border-width: 1px;
}

.ec-step.is-simple .ec-step__main {
  flex-direction: row;
  align-items: center;
  padding-left: 0;
}

.ec-step.is-simple .ec-step__title {
  line-height: 1;
  font-size: var(--ec-font-size-base);
}

.ec-step.is-simple:not(:last-of-type)::after {
  content: '';
  flex: 1;
  height: 1px;
  margin: 0 12px;
  background-color: var(--ec-steps-line-color);
}
